@@ -7,6 +7,10 @@ import type { MutateFn } from "../lib/sse";
 const NOOP_MUTATE = (() => undefined) as MutateFn;
 const DEDUPE_WINDOW = 256;

+/**
+ * Synchronizes toast notifications with a run-scoped SSE stream. Changing
